- `src/services/skills/skill-cache-service.ts`
- `src/commands/skills/add.ts`

## Acceptance Criteria
- [ ] Skills with only SKILL.md can be added
- [ ] Frontmatter parsed into manifest fields
- [ ] Works for both GitHub and local sources

design:
**Current State (src/commands/templates.ts:103-144):**
- `templates apply` extracts variables with defaults
- Only applies defaults, ignores CLI input
- No `templates vars` subcommand

**Implementation:**

1. **Add `templates vars` subcommand:**
```typescript
case "vars": {
  if (!targetArg) {
    console.log("Usage: grimoire templates vars <name-or-id>");
    return;
  }

  const template = yield* storage.getById(targetArg).pipe(
    Effect.catchTag("PromptNotFoundError", () =>
      storage.getByName(targetArg)
    )
  );

  if (!template.isTemplate) {
    console.log("Error: Not a template");
    return;
  }

  const vars = extractVariablesWithDefaults(template.content);

  console.log(`Template: ${template.name}`);
  console.log(`\nVariables:`);

  if (Object.keys(vars).length === 0) {
    console.log("  (none)");
  } else {
    console.log("NAME".padEnd(20) + "DEFAULT");
    console.log("-".repeat(40));
    for (const [name, defaultVal] of Object.entries(vars)) {
      const def = defaultVal || "(required)";
      console.log(`${name.padEnd(20)}${def}`);
    }
  }
  break;
}
```

2. **Update `templates apply` to accept `--var` flags:**
```typescript
case "apply": {
  // ... existing code ...

  // Parse CLI variable overrides
  const cliVars: Record<string, string> = {};
  const varFlags = args.flags["var"];
  if (typeof varFlags === "string") {
    const [key, value] = varFlags.split("=", 2);
    if (key && value !== undefined) cliVars[key] = value;
  } else if (Array.isArray(varFlags)) {
    for (const v of varFlags) {
      const [key, value] = v.split("=", 2);
      if (key && value !== undefined) cliVars[key] = value;
    }
  }

  // Merge: CLI overrides > defaults
  const vars = extractVariablesWithDefaults(template.content);
  let content = template.content;

  for (const [varName, defaultVal] of Object.entries(vars)) {
    const value = cliVars[varName] ?? defaultVal;
    if (!value) {
      console.error(`Error: Missing required variable: ${varName}`);
      return;
    }
    content = content.replace(
      new RegExp(`\\{\\{${varName}(?::[^}]*)?\\}\\}`, "g"),
      value
    );
  }
  // ... rest of apply logic
}
```

**Usage:**
```bash
grimoire templates vars my-template
# Template: my-template
# Variables:
# NAME                DEFAULT
# ----------------------------------------
# name                (required)
# greeting            Hello
# company             Acme Inc

grimoire templates apply my-template --var name=John --var company="My Corp"
```

